-- Adrasan Beltom Beach Hotel: oda görselleri + TatilBudur afiş fiyatı (Standart Oda)
-- Kaynak: TatilBudur 20–25 Temmuz 2026, 2 yetişkin, 5 gece = 30.000 TL → 6.000 TL/gece
-- Uygula: ./deploy/apply-sql.sh deploy/scripts/sql/update-adrasan-beltom-rooms.sql
BEGIN;
DELETE FROM hotel_rooms WHERE listing_id = (SELECT id FROM listings WHERE external_provider_code = 'tatilbudur' AND external_listing_ref = 'adrasan-beltom-beach-hotel' LIMIT 1);
INSERT INTO hotel_rooms (listing_id, name, capacity, board_type, meta_json, unit_count)
    VALUES ((SELECT id FROM listings WHERE external_provider_code = 'tatilbudur' AND external_listing_ref = 'adrasan-beltom-beach-hotel' LIMIT 1), 'Standart Oda', 3, 'Yarım Pansiyon', '{"tatilbudur_room_type_id":"standart-oda","image":"https://www.beltomhotel.com/Upload/beltom/tr/odalar/standart-oda/img/big/standart-oda-37a91.jpg","images":["https://www.beltomhotel.com/Upload/beltom/tr/odalar/standart-oda/img/big/standart-oda-37a91.jpg","https://www.beltomhotel.com/Upload/beltom/tr/odalar/standart-oda/img_gallery/img/big/deluxe-havuz-manzara-1d6d4.jpg","https://www.beltomhotel.com/Upload/beltom/tr/odalar/standart-oda/img_gallery/img/big/deluxe-havuz-manzara-d2cb1.jpg"],"features":["Balkon","Emanet kasa","Mini bar","Saç kurutma makinesi","Split klima","Telefon","Wi-Fi","Özel banyo"],"seasonal_prices":[{"validFrom":"2026-07-01","validTo":"2026-09-15","nightlyPrice":6000,"currency":"TRY","boardType":"Yarım Pansiyon"}],"price_source":"tatilbudur","price_quote":{"checkIn":"2026-07-20","checkOut":"2026-07-25","nights":5,"adults":2,"boardType":"Yarım Pansiyon","totalTry":30000,"nightlyTry":6000,"note":"TatilBudur Adrasan oteller listesi (20–25 Temmuz 2026, 2 yetişkin, 5 gece, 30.000 TL toplam) afiş fiyatından gecelik 6.000 TL. Oda tipi ayrımı yayınlanmadığı için fiyat yalnızca Standart Oda’ya yazıldı; diğer oda tiplerinde yalnızca görseller güncellendi."}}'::jsonb, 1);
INSERT INTO hotel_rooms (listing_id, name, capacity, board_type, meta_json, unit_count)
    VALUES ((SELECT id FROM listings WHERE external_provider_code = 'tatilbudur' AND external_listing_ref = 'adrasan-beltom-beach-hotel' LIMIT 1), 'Ranzalı Aile Odası', 4, 'Yarım Pansiyon', '{"tatilbudur_room_type_id":"ranzali-aile-odasi","image":"https://www.beltomhotel.com/Upload/beltom/tr/odalar/ranzali-aile-odasi/img/big/ranzali-aile-odasi-ec6d2.jpg","images":["https://www.beltomhotel.com/Upload/beltom/tr/odalar/ranzali-aile-odasi/img/big/ranzali-aile-odasi-ec6d2.jpg","https://www.beltomhotel.com/Upload/beltom/tr/odalar/ranzali-aile-odasi/img_gallery/img/big/deniz-manzarali-standart-genis-oda-cf0f2.jpg"],"features":["Ranza","Balkon","Emanet kasa","Mini bar","Saç kurutma makinesi","Split klima","Telefon","Wi-Fi","Özel banyo"],"seasonal_prices":[],"price_source":"tatilbudur","price_quote":{"checkIn":"2026-07-20","checkOut":"2026-07-25","nights":5,"adults":2,"boardType":"Yarım Pansiyon","totalTry":30000,"nightlyTry":6000,"note":"TatilBudur Adrasan oteller listesi (20–25 Temmuz 2026, 2 yetişkin, 5 gece, 30.000 TL toplam) afiş fiyatından gecelik 6.000 TL. Oda tipi ayrımı yayınlanmadığı için fiyat yalnızca Standart Oda’ya yazıldı; diğer oda tiplerinde yalnızca görseller güncellendi."}}'::jsonb, 1);
INSERT INTO hotel_rooms (listing_id, name, capacity, board_type, meta_json, unit_count)
    VALUES ((SELECT id FROM listings WHERE external_provider_code = 'tatilbudur' AND external_listing_ref = 'adrasan-beltom-beach-hotel' LIMIT 1), 'Ara Kapılı Aile Suit', 5, 'Yarım Pansiyon', '{"tatilbudur_room_type_id":"ara-kapili-aile-suit","image":"https://www.beltomhotel.com/Upload/beltom/tr/odalar/ara-kapili-aile-suit/img/big/ara-kapili-aile-suit-48f20.png","images":["https://www.beltomhotel.com/Upload/beltom/tr/odalar/ara-kapili-aile-suit/img/big/ara-kapili-aile-suit-48f20.png","https://www.beltomhotel.com/Upload/beltom/tr/odalar/ara-kapili-aile-suit/img_gallery/img/big/deniz-manzarali-aile-odasi-17f34.png"],"features":["Ara kapılı oda","Balkon","Emanet kasa","Mini bar","Saç kurutma makinesi","Split klima","Telefon","Wi-Fi","Özel banyo"],"seasonal_prices":[],"price_source":"tatilbudur","price_quote":{"checkIn":"2026-07-20","checkOut":"2026-07-25","nights":5,"adults":2,"boardType":"Yarım Pansiyon","totalTry":30000,"nightlyTry":6000,"note":"TatilBudur Adrasan oteller listesi (20–25 Temmuz 2026, 2 yetişkin, 5 gece, 30.000 TL toplam) afiş fiyatından gecelik 6.000 TL. Oda tipi ayrımı yayınlanmadığı için fiyat yalnızca Standart Oda’ya yazıldı; diğer oda tiplerinde yalnızca görseller güncellendi."}}'::jsonb, 1);
INSERT INTO hotel_rooms (listing_id, name, capacity, board_type, meta_json, unit_count)
    VALUES ((SELECT id FROM listings WHERE external_provider_code = 'tatilbudur' AND external_listing_ref = 'adrasan-beltom-beach-hotel' LIMIT 1), 'King Suit', 4, 'Yarım Pansiyon', '{"tatilbudur_room_type_id":"king-suit","image":"https://www.beltomhotel.com/Upload/beltom/tr/odalar/king-suit/img/big/king-suit-ef100.png","images":["https://www.beltomhotel.com/Upload/beltom/tr/odalar/king-suit/img/big/king-suit-ef100.png","https://www.beltomhotel.com/Upload/beltom/tr/odalar/king-suit/img_gallery/img/big/kara-manzarali-aile-odasi-7b4cd.png","https://www.beltomhotel.com/Upload/beltom/tr/odalar/king-suit/img_gallery/img/big/kara-manzarali-aile-odasi-1dc24.png","https://www.beltomhotel.com/Upload/beltom/tr/odalar/king-suit/img_gallery/img/big/kara-manzarali-aile-odasi-9a198.png"],"features":["Geniş yaşam alanı","Oturma alanı","Mini bar","Split klima","Wi-Fi","Özel banyo","Doğa manzarası"],"seasonal_prices":[],"price_source":"tatilbudur","price_quote":{"checkIn":"2026-07-20","checkOut":"2026-07-25","nights":5,"adults":2,"boardType":"Yarım Pansiyon","totalTry":30000,"nightlyTry":6000,"note":"TatilBudur Adrasan oteller listesi (20–25 Temmuz 2026, 2 yetişkin, 5 gece, 30.000 TL toplam) afiş fiyatından gecelik 6.000 TL. Oda tipi ayrımı yayınlanmadığı için fiyat yalnızca Standart Oda’ya yazıldı; diğer oda tiplerinde yalnızca görseller güncellendi."}}'::jsonb, 1);
DELETE FROM listing_price_rules WHERE listing_id = (SELECT id FROM listings WHERE external_provider_code = 'tatilbudur' AND external_listing_ref = 'adrasan-beltom-beach-hotel' LIMIT 1) AND rule_json->>'source' = 'tatilbudur';
INSERT INTO listing_price_rules (listing_id, rule_json, valid_from, valid_to)
      VALUES ((SELECT id FROM listings WHERE external_provider_code = 'tatilbudur' AND external_listing_ref = 'adrasan-beltom-beach-hotel' LIMIT 1), '{"source":"tatilbudur","base_nightly":"6000","base_price":"6000","currency":"TRY","room_type_id":"standart-oda","room_name":"Standart Oda","board_type":"Yarım Pansiyon"}'::jsonb, '2026-07-01'::date, '2026-09-15'::date);
UPDATE listings SET
  vitrin_price = 6000,
  currency_code = 'TRY',
  slug = CASE
    WHEN slug LIKE '%-tb-%'
      AND NOT EXISTS (SELECT 1 FROM listings o WHERE o.slug = 'adrasan-beltom-beach-hotel' AND o.id <> listings.id)
    THEN 'adrasan-beltom-beach-hotel'
    ELSE slug
  END,
  last_synced_at = now(),
  updated_at = now()
WHERE id = (SELECT id FROM listings WHERE external_provider_code = 'tatilbudur' AND external_listing_ref = 'adrasan-beltom-beach-hotel' LIMIT 1);
INSERT INTO listing_attributes (listing_id, group_code, key, value_json)
  VALUES ((SELECT id FROM listings WHERE external_provider_code = 'tatilbudur' AND external_listing_ref = 'adrasan-beltom-beach-hotel' LIMIT 1), 'tatilbudur', 'snapshot', '{"id":"adrasan-beltom-beach-hotel","name":"Adrasan Beltom Beach Hotel","slug":"adrasan-beltom-beach-hotel","url":"https://www.tatilbudur.com/adrasan-beltom-beach-hotel","officialUrl":"https://www.beltomhotel.com/tr/otelimiz","countryCode":"TR","city":"Antalya","district":"Kumluca / Adrasan","address":"Adrasan Mah. Semt 130 Sokak No: 22, Çavuşköy, 07370 Kumluca/Antalya","currency":"TRY","description":"<section><h2>Adrasan’da doğa ve denizle iç içe konaklama</h2><p>Adrasan Beltom Beach Hotel, Antalya’nın Kumluca ilçesine bağlı Adrasan’da, sakin bir kıyı atmosferinde konaklama sunar. Tesis; aileler, çocuklu misafirler ve deniz tatilini doğayla birleştirmek isteyen konuklar için uygun olanaklara sahiptir.</p><h2>Plaj ve havuz olanakları</h2><p>Tesise ait kum plaj yaklaşık 400 metre mesafededir. Plajdaki şezlong ve şemsiyeler ücretsizdir; plajda tesise ait yiyecek-içecek servisi bulunmaz.</p><ul><li>Özel kum plaj</li><li>Açık yüzme havuzu ve çocuk havuzu</li><li>Tek bantlı su kaydırağı</li><li>Çocuk oyun alanı</li></ul><h2>Yeme ve içme</h2><p>Yarım pansiyon konseptinde açık büfe kahvaltı ve akşam yemeği sunulur. Havuz bar ve restoran bar hizmetleri ücretlidir. Konsept dışında alınan yiyecek ve içecekler ayrıca ücretlendirilir.</p><h2>Konum</h2><p>Otel; Antalya şehir merkezine yaklaşık 93 km, Antalya Havalimanı’na 109 km ve Antalya Otogarı’na 93,8 km uzaklıktadır.</p>","amenities":["Özel kum plaj","Ücretsiz şezlong ve şemsiye","Açık havuz","Çocuk havuzu","Tek bantlı su kaydırağı","Çocuk oyun alanı","Otopark","Emanet kasa","Ön büro","Yarım pansiyon","Ücretli çamaşırhane","Ücretli transfer hizmeti","Ücretli su sporları","Ücretli plaj havlusu"],"images":["https://beltomhotel.com/Upload/beltom/tr/fotograf-galeri/genel-fotograflar/img_gallery/img/big/genel-fotograflar-5561f.jpg","https://beltomhotel.com/Uplo