odalar/ara-kapili-aile-suit/img_gallery/img/big/deniz-manzarali-aile-odasi-17f34.png"],"features":["Ara kapılı oda","Balkon","Emanet kasa","Mini bar","Saç kurutma makinesi","Split klima","Telefon","Wi-Fi","Özel banyo"]},{"id":"king-suit","name":"King Suit","capacity":4,"boardType":"Yarım Pansiyon","image":"https://www.beltomhotel.com/Upload/beltom/tr/odalar/king-suit/img/big/king-suit-ef100.png","images":["https://www.beltomhotel.com/Upload/beltom/tr/odalar/king-suit/img/big/king-suit-ef100.png","https://www.beltomhotel.com/Upload/beltom/tr/odalar/king-suit/img_gallery/img/big/kara-manzarali-aile-odasi-7b4cd.png","https://www.beltomhotel.com/Upload/beltom/tr/odalar/king-suit/img_gallery/img/big/kara-manzarali-aile-odasi-1dc24.png","https://www.beltomhotel.com/Upload/beltom/tr/odalar/king-suit/img_gallery/img/big/kara-manzarali-aile-odasi-9a198.png"],"features":["Geniş yaşam alanı","Oturma alanı","Mini bar","Split klima","Wi-Fi","Özel banyo","Doğa manzarası"]}],"sourceFacts":{"tourismApplicationDocument":"G_20696","beachDistanceMeters":400,"antalyaCenterDistanceKm":93,"antalyaAirportDistanceKm":109,"antalyaBusTerminalDistanceKm":93.8,"mealPlan":"Yarım Pansiyon","breakfastHours":"08:00-10:00","dinnerHours":"19:00-21:00","priceSource":"tatilbudur","priceQuote":{"checkIn":"2026-07-20","checkOut":"2026-07-25","nights":5,"adults":2,"boardType":"Yarım Pansiyon","totalTry":30000,"nightlyTry":6000,"note":"TatilBudur Adrasan oteller listesi (20–25 Temmuz 2026, 2 yetişkin, 5 gece, 30.000 TL toplam) afiş fiyatından gecelik 6.000 TL. Oda tipi ayrımı yayınlanmadığı için fiyat yalnızca Standart Oda’ya yazıldı; diğer oda tiplerinde yalnızca görseller güncellendi."},"verifiedAt":"2026-07-20"},"rooms_updated_at":"2026-07-20T18:12:31.771Z"}'::jsonb)
  ON CONFLICT (listing_id, group_code, key) DO UPDATE SET value_json = EXCLUDED.value_json;
SELECT refresh_listing_vitrin_prices();
SELECT l.slug, l.status, l.vitrin_price::text,
  count(hr.id) AS rooms,
  count(hr.id) FILTER (WHERE nullif(hr.meta_json->>'image','') IS NOT NULL) AS rooms_with_images
FROM listings l
LEFT JOIN hotel_rooms hr ON hr.listing_id = l.id
WHERE l.external_provider_code = 'tatilbudur' AND l.external_listing_ref = 'adrasan-beltom-beach-hotel'
GROUP BY l.id;
COMMIT;
